class DocumentProcessor:
    def __init__(self, documents_path):
        self.documents = {}
        self.load_documents(documents_path)

    def load_documents(self, path):
        """Load all sample documents"""
        doc_files = {
            'sample_personal_info': 'sample_personal_info.txt',
            'sample_application': 'sample_application.txt', 
            'sample_resume': 'sample_resume.txt'
        }

        for doc_name, filename in doc_files.items():
