    def extract_information(self):
        """Extract structured information using regex patterns"""
        extracted_data = {}

        name_candidates = set()
        phone_candidates = set()
        email_candidates = set()
        address_candidates = set()

        for doc_name, content in self.documents.items():
            data = {}

            # Names - collect all possible variations
            name_patterns = [
                r'(?:Full Name|Name):\s*([A-Za-z\s]+\s+[A-Za-z\s]+)',
