                r'^([A-Za-z]+\s+[A-Za-z]+)$'
            ]
            for pattern in name_patterns:
                matches = re.findall(pattern, content, re.IGNORECASE | re.MULTILINE)
                for match in matches:
                    if len(match.strip()) > 3:
                        name_candidates.add(match.strip())

            # Take the most common name
