            addr_matches = re.findall(r'(?:Address|Current Address).*?:\s*(.*?)(?:\n[A-Z]|\n\n|$)', content, re.IGNORECASE | re.DOTALL)
            if addr_matches:
                for addr in addr_matches:
                    addr = re.sub(r'^\s*[-*]\s*|^\s*/', '', addr)  # Remove bullets and dashes
                    addr = re.sub(r'\s+', ' ', addr).strip()
                    if len(addr) > 20 and any(char.isdigit() for char in addr):
                        address_candidates.add(addr)
                        data['address'] = addr
                        break

            # Company/Organization
            company_patterns = [
                r'(?:Current Employer|Company):\s*([^\n]+)',
                r'(?:^|\n)\s*([A-Za-z\s]+?Corp|Inc|Company|Org|Tech)\s*$'
            ]
